import javax.servlet.ServletException;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.OutputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

@WebServlet("/download")
public class FileDownloadServlet extends HttpServlet {

    private static final String UPLOAD_DIR = "uploads";
    private Path uploadBasePath;

    @Override
    public void init() throws ServletException {
        super.init();
        String realPath = getServletContext().getRealPath("/" + UPLOAD_DIR);
        if (realPath == null) {
            realPath = System.getProperty("user.dir") + File.separator + UPLOAD_DIR;
        }
        try {
            uploadBasePath = Paths.get(realPath).toRealPath();
            File uploadDir = uploadBasePath.toFile();
            if (!uploadDir.exists()) {
                uploadDir.mkdirs();
            }
        } catch (IOException e) {
            throw new ServletException("Failed to initialize upload directory", e);
        }
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String filename = request.getParameter("filename");

        if (filename == null || filename.trim().isEmpty()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Filename parameter is required");
            return;
        }

        filename = filename.trim();

        if (filename.contains("..") || filename.contains("/") || filename.contains("\\")) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid filename");
            return;
        }

        Path requestedFilePath = uploadBasePath.resolve(filename);

        try {
            requestedFilePath = requestedFilePath.toRealPath();
        } catch (IOException e) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND, "File not found");
            return;
        }

        if (!requestedFilePath.startsWith(uploadBasePath)) {
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        File file = requestedFilePath.toFile();

        if (!file.exists() || !file.isFile()) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND, "File not found");
            return;
        }

        if (!file.canRead()) {
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Cannot read file");
            return;
        }

        String mimeType = getServletContext().getMimeType(file.getName());
        if (mimeType == null) {
            mimeType = determineMimeType(file.getName());
        }

        response.setContentType(mimeType);
        response.setContentLengthLong(file.length());
        response.setHeader("Content-Disposition", "inline; filename=\"" + sanitizeFilename(file.getName()) + "\"");

        try (FileInputStream fileInputStream = new FileInputStream(file);
             OutputStream outputStream = response.getOutputStream()) {

            byte[] buffer = new byte[8192];
            int bytesRead;

            while ((bytesRead = fileInputStream.read(buffer)) != -1) {
                outputStream.write(buffer, 0, bytesRead);
            }

            outputStream.flush();
        } catch (IOException e) {
            throw new ServletException("Error serving file", e);
        }
    }

    private String determineMimeType(String filename) {
        String lowerFilename = filename.toLowerCase();

        if (lowerFilename.endsWith(".pdf")) {
            return "application/pdf";
        } else if (lowerFilename.endsWith(".jpg") || lowerFilename.endsWith(".jpeg")) {
            return "image/jpeg";
        } else if (lowerFilename.endsWith(".png")) {
            return "image/png";
        } else if (lowerFilename.endsWith(".gif")) {
            return "image/gif";
        } else if (lowerFilename.endsWith(".bmp")) {
            return "image/bmp";
        } else if (lowerFilename.endsWith(".doc")) {
            return "application/msword";
        } else if (lowerFilename.endsWith(".docx")) {
            return "application/vnd.openxmlformats-officedocument.wordprocessingml.document";
        } else if (lowerFilename.endsWith(".xls")) {
            return "application/vnd.ms-excel";
        } else if (lowerFilename.endsWith(".xlsx")) {
            return "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
        } else if (lowerFilename.endsWith(".txt")) {
            return "text/plain";
        } else if (lowerFilename.endsWith(".html") || lowerFilename.endsWith(".htm")) {
            return "text/html";
        } else {
            return "application/octet-stream";
        }
    }

    private String sanitizeFilename(String filename) {
        return filename.replaceAll("[\"\\\\]", "");
    }
}